class Solution:
    def numEnclaves(self, grid):
        m = len(grid)
        n = len(grid[0])
        from collections import deque
        reach = [[False] * n for _ in range(m)]
        q = deque()
        for i in range(m):
            for j in range(n):
                if (i == 0 or i == m - 1 or j == 0 or j == n - 1) and grid[i][j] == 1:
                    reach[i][j] = True
                    q.append((i, j))
        while q:
            i, j = q.popleft()
            for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and grid[ni][nj] == 1 and not reach[ni][nj]:
                    reach[ni][nj] = True
                    q.append((ni, nj))
        count = 0
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1 and not reach[i][j]:
                    count += 1
        return count

