import sys
class Solution:
    def numEnclaves(self, grid):
        sys.setrecursionlimit(300000)
        m = len(grid)
        n = len(grid[0])
        def fill(i, j):
            stack = [(i, j)]
            while stack:
                x, y = stack.pop()
                if 0 <= x < m and 0 <= y < n and grid[x][y] == 1:
                    grid[x][y] = 0
                    stack.extend([(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)])
        for j in range(n):
            fill(0, j)
            fill(m - 1, j)
        for i in range(m):
            fill(i, 0)
            fill(i, n - 1)
        return sum(row.count(1) for row in grid)

