var numEnclaves = function(grid) {
    const m = grid.length, n = grid[0].length;
    const fill = (i, j) => {
        const stack = [[i, j]];
        while (stack.length) {
            const [x, y] = stack.pop();
            if (x >= 0 && x < m && y >= 0 && y < n && grid[x][y] === 1) {
                grid[x][y] = 0;
                stack.push([x + 1, y], [x - 1, y], [x, y + 1], [x, y - 1]);
            }
        }
    };
    for (let j = 0; j < n; j++) { fill(0, j); fill(m - 1, j); }
    for (let i = 0; i < m; i++) { fill(i, 0); fill(i, n - 1); }
    let count = 0;
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) if (grid[i][j] === 1) count++;
    return count;
};
